import React, { useState, useEffect, useRef } from 'react';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);
  const containerRef = useRef(null);
  const [positions, setPositions] = useState([]);

  const allSkills = [
    { name: 'HTML5', icon: '🌐' },
    { name: 'CSS3', icon: '🎨' },
    { name: 'JavaScript', icon: '⚡' },
    { name: 'TypeScript', icon: '📘' },
    { name: 'React', icon: '⚛️' },
    { name: 'Next.js', icon: '▲' },
    { name: 'Tailwind CSS', icon: '💨' },
    { name: 'Redux', icon: '🔄' },
    { name: 'Framer Motion', icon: '🎬' },
    { name: 'Node.js', icon: '🟢' },
    { name: 'Express.js', icon: '🚀' },
    { name: 'MongoDB', icon: '🍃' },
    { name: 'MySQL', icon: '🐬' },
    { name: 'PostgreSQL', icon: '🐘' },
    { name: 'Firebase', icon: '🔥' },
    { name: 'JWT', icon: '🔐' },
    { name: 'REST API', icon: '🔗' },
    { name: 'Socket.io', icon: '📡' },
    { name: 'Java', icon: '☕' },
    { name: 'Python', icon: '🐍' },
    { name: 'C++', icon: '⚙️' },
    { name: 'C', icon: '🔧' },
    { name: 'C#', icon: '🎯' },
    { name: 'PHP', icon: '🐘' },
    { name: 'Git', icon: '🔀' },
    { name: 'GitHub', icon: '🐙' },
    { name: 'Docker', icon: '🐳' },
    { name: 'Linux', icon: '🐧' },
    { name: 'VS Code', icon: '💻' },
    { name: 'Postman', icon: '📮' },
    { name: 'Figma', icon: '🎯' }
  ];

  // Initialize positions
  useEffect(() => {
    const initialPositions = allSkills.map(() => ({
      x: 5 + Math.random() * 85,
      y: 5 + Math.random() * 85,
      speedX: (Math.random() - 0.5) * 0.5,
      speedY: (Math.random() - 0.5) * 0.5,
      size: 50 + Math.random() * 30,
      rotation: Math.random() * 360,
      rotSpeed: (Math.random() - 0.5) * 0.3
    }));
    setPositions(initialPositions);
  }, []);

  // Both X and Y axis movement animation
  useEffect(() => {
    if (positions.length === 0) return;

    let animationId;

    const animateBoth = () => {
      setPositions(prev => 
        prev.map((pos) => {
          let newX = pos.x + pos.speedX * 0.25;
          let newY = pos.y + pos.speedY * 0.25;

          // Bounce off X edges
          if (newX > 95 || newX < 3) {
            pos.speedX *= -1;
            newX = pos.x + pos.speedX * 0.25;
          }
          // Bounce off Y edges
          if (newY > 95 || newY < 3) {
            pos.speedY *= -1;
            newY = pos.y + pos.speedY * 0.25;
          }

          // Random direction change occasionally
          if (Math.random() < 0.002) {
            pos.speedX += (Math.random() - 0.5) * 0.1;
            pos.speedY += (Math.random() - 0.5) * 0.1;
            // Limit speed
            pos.speedX = Math.max(-0.6, Math.min(0.6, pos.speedX));
            pos.speedY = Math.max(-0.6, Math.min(0.6, pos.speedY));
          }

          return {
            ...pos,
            x: newX,
            y: newY,
            rotation: pos.rotation + pos.rotSpeed * 0.5
          };
        })
      );

      animationId = requestAnimationFrame(animateBoth);
    };

    const timeout = setTimeout(() => {
      animateBoth();
    }, 500);

    return () => {
      clearTimeout(timeout);
      if (animationId) cancelAnimationFrame(animationId);
    };
  }, [positions.length]);

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden min-h-screen">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div 
          ref={containerRef}
          className="relative min-h-[600px] w-full overflow-hidden rounded-3xl"
          style={{
            background: 'radial-gradient(ellipse at center, rgba(139,92,246,0.03) 0%, transparent 70%)'
          }}
        >
          {/* Movement Grid Background */}
          <div className="absolute inset-0 pointer-events-none opacity-5">
            {[...Array(6)].map((_, i) => (
              <div
                key={`v-${i}`}
                className="absolute w-px h-full bg-purple-500"
                style={{ left: `${(i + 1) * 16}%` }}
              />
            ))}
            {[...Array(6)].map((_, i) => (
              <div
                key={`h-${i}`}
                className="absolute w-full h-px bg-purple-500"
                style={{ top: `${(i + 1) * 16}%` }}
              />
            ))}
          </div>

          {/* Floating Particles Background */}
          <div className="absolute inset-0 pointer-events-none">
            {[...Array(20)].map((_, i) => (
              <div
                key={i}
                className="absolute rounded-full bg-purple-400/5"
                style={{
                  width: 2 + Math.random() * 4,
                  height: 2 + Math.random() * 4,
                  top: `${Math.random() * 100}%`,
                  left: `${Math.random() * 100}%`,
                  animation: `floatParticle ${15 + Math.random() * 20}s linear infinite`,
                  animationDelay: `${Math.random() * 10}s`
                }}
              />
            ))}
          </div>

          {/* Skills - Moving on Both X and Y Axis */}
          <div className="relative w-full h-full">
            {positions.map((pos, index) => {
              const skill = allSkills[index];
              if (!skill) return null;

              const isHovered = hoveredSkill === skill.name;

              return (
                <div
                  key={skill.name}
                  className="absolute cursor-pointer transition-all duration-300"
                  style={{
                    left: `${pos.x}%`,
                    top: `${pos.y}%`,
                    transform: `translate(-50%, -50%) rotate(${pos.rotation}deg)`,
                    zIndex: isHovered ? 50 : 10,
                    opacity: isHovered ? 1 : 0.6
                  }}
                  onMouseEnter={() => setHoveredSkill(skill.name)}
                  onMouseLeave={() => setHoveredSkill(null)}
                >
                  <div
                    className="flex flex-col items-center justify-center rounded-full transition-all duration-300"
                    style={{
                      width: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                      height: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                      boxShadow: isHovered 
                        ? '0 0 60px rgba(139,92,246,0.4), 0 0 120px rgba(139,92,246,0.15)' 
                        : 'none',
                      background: isHovered 
                        ? 'rgba(26,31,46,0.9)' 
                        : 'rgba(26,31,46,0.15)',
                      border: isHovered 
                        ? '1.5px solid rgba(139,92,246,0.5)' 
                        : '1px solid rgba(255,255,255,0.03)',
                      transform: isHovered ? 'scale(1.2)' : 'scale(1)'
                    }}
                  >
                    <span
                      className="transition-all duration-300"
                      style={{
                        fontSize: isHovered ? '30px' : '18px',
                        filter: isHovered 
                          ? 'brightness(1.3) drop-shadow(0 0 20px rgba(139,92,246,0.3))' 
                          : 'brightness(0.7)'
                      }}
                    >
                      {skill.icon}
                    </span>

                    {isHovered && (
                      <span className="text-[9px] font-semibold text-white mt-0.5 animate-fadeIn">
                        {skill.name}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
            <div className="text-[10px] text-gray-500">Happy Clients</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
